      {
        "path": "App.css",
        "content": "@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@600;700&family=DM+Sans:ital,wght@0,300;0,400;0,500;0,600;1,400&display=swap');

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg:       #080812;
  --surface:  #10101e;
  --card:     #13132a;
  --border:   #1e1e3a;
  --border2:  #2d2d5a;
  --gold:     #e8c07a;
  --gold2:    #c8913a;
  --violet:   #8070f8;
  --violet2:  #5548c8;
  --teal:     #3ecfca;
  --teal2:    #269c98;
  --text:     #eeeaf8;
  --text2:    #9090b8;
  --text3:    #5858a0;
  --err:      #ff5a5a;
  --shadow:   0 12px 40px rgba(0,0,0,0.7);
  --r:        12px;
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: 'DM Sans', sans-serif;
  min-height: 100vh;
  overflow-x: hidden;
}

/* ── Loading ── */
.loading {
  display: flex; flex-direction: column; align-items: center;
  justify-content: center; gap: 16px; height: 100vh;
  font-size: 1.1rem; color: var(--gold);
}
.loading-spinner {
  width: 36px; height: 36px;
  border: 3px solid var(--border2);
  border-top-color: var(--violet);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

/* ── Background ── */
.bg-canvas {
  position: fixed; inset: 0; z-index: 0;
  pointer-events: none; overflow: hidden;
}
.orb {
  position: absolute; border-radius: 50%;
  filter: blur(90px); opacity: 0.13;
}
.orb1 { width: 700px; height: 700px; background: var(--violet); top: -250px; left: -250px; animation: drift1 14s ease-in-out infinite; }
.orb2 { width: 550px; height: 550px; background: var(--gold);   top: 35%; right: -200px; animation: drift2 17s ease-in-out infinite; }
.orb3 { width: 450px; height: 450px; background: var(--teal);   bottom: -150px; left: 25%; animation: drift3 11s ease-in-out infinite; }
@keyframes drift1 { 0%,100%{transform:translate(0,0)}  50%{transform:translate(50px,35px)} }
@keyframes drift2 { 0%,100%{transform:translate(0,0)}  50%{transform:translate(-40px,50px)} }
@keyframes drift3 { 0%,100%{transform:translate(0,0)}  50%{transform:translate(25px,-35px)} }
.grid-lines {
  position: absolute; inset: 0;
  background-image:
    linear-gradient(rgba(112,96,248,0.04) 1px, transparent 1px),
    linear-gradient(90deg, rgba(112,96,248,0.04) 1px, transparent 1px);
  background-size: 40px 40px;
}

/* ── App shell ── */
.app {
  position: relative; z-index: 1;
  min-height: 100vh;
  display: flex; flex-direction: column; align-items: center;
  padding: 0 16px 60px;
}

/* ── Header ── */
.header {
  width: 100%; max-width: 960px;
  display: flex; justify-content: space-between; align-items: center;
  padding: 28px 0 20px;
}
.logo { display: flex; align-items: center; gap: 10px; }
.logo-symbol {
  font-size: 1.8rem;
  background: linear-gradient(135deg, var(--gold), var(--violet));
  -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
  animation: pulse 3s ease-in-out infinite;
}
@keyframes pulse { 0%,100%{opacity:1} 50%{opacity:0.6} }
.logo-text {
  font-family: 'Playfair Display', serif;
  font-size: 2rem; font-weight: 700; letter-spacing: 0.22em;
  background: linear-gradient(135deg, var(--gold), var(--violet));
  -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
}
.header-stats { display: flex; gap: 12px; }
.stat-chip {
  display: flex; align-items: center; gap: 6px;
  background: var(--card); border: 1px solid var(--border2);
  border-radius: 20px; padding: 6px 14px;
  font-size: 1rem; font-weight: 500;
}
.stat-icon { font-size: 0.9rem; }
.stat-val { color: var(--teal); font-variant-numeric: tabular-nums; letter-spacing: 0.05em; }

/* ── Toolbar ── */
.toolbar {
  display: flex; gap: 10px; align-items: center;
  margin-bottom: 28px; flex-wrap: wrap; justify-content: center;
}
.diff-group { display: flex; gap: 6px; }
.diff-btn {
  padding: 7px 18px;
  background: var(--card); border: 1.5px solid var(--border2);
  color: var(--text2); border-radius: 24px;
  font-family: 'DM Sans'; font-size: 0.88rem;
  cursor: pointer; transition: all 0.2s;
}
.diff-btn:hover { color: var(--text); border-color: var(--violet); }
.diff-btn.active {
  background: linear-gradient(135deg, var(--violet2), var(--violet));
  border-color: transparent; color: #fff; font-weight: 600;
  box-shadow: 0 0 16px rgba(128,112,248,0.4);
}
.new-btn {
  padding: 8px 22px;
  background: linear-gradient(135deg, var(--gold2), var(--gold));
  border: none; color: #0a0a18;
  font-family: 'DM Sans'; font-weight: 700; font-size: 0.9rem;
  border-radius: 24px; cursor: pointer; transition: all 0.2s;
  letter-spacing: 0.04em;
}
.new-btn:hover { transform: translateY(-2px); box-shadow: 0 4px 18px rgba(232,192,122,0.45); }

/* ── Game layout ── */
.game-layout {
  display: flex; gap: 32px; align-items: flex-start;
  flex-wrap: wrap; justify-content: center;
  width: 100%; max-width: 960px;
}

/* ── Board ── */
.board-container { position: relative; }

.board {
  display: grid;
  grid-template-columns: repeat(9, 1fr);
  gap: 2px;
  background: var(--border);
  border: 3px solid var(--violet2);
  border-radius: var(--r);
  overflow: hidden;
  width: clamp(288px, min(90vw, 504px), 504px);
  height: clamp(288px, min(90vw, 504px), 504px);
  box-shadow:
    0 0 0 1px var(--violet),
    0 0 50px rgba(128,112,248,0.25),
    var(--shadow);
}

/* ── Cells ── */
.cell {
  background: var(--surface);
  display: flex; align-items: center; justify-content: center;
  cursor: pointer; position: relative;
  transition: background 0.12s, transform 0.08s;
  user-select: none;
}
.cell.editable:hover { background: #181830; }
.cell.highlighted { background: #14142a; }
.cell.same-val {
  background: #1c1c38;
}
.cell.selected {
  background: rgba(128,112,248,0.22) !important;
  box-shadow: inset 0 0 0 2px var(--violet);
  z-index: 2;
}
.cell.error { background: rgba(255,90,90,0.12); }
.cell.error .cell-val { color: var(--err) !important; }
.cell.hinted .cell-val { color: var(--teal) !important; }
.cell.shake { animation: shakeIt 0.4s cubic-bezier(.36,.07,.19,.97); }
@keyframes shakeIt {
  0%,100%{transform:translateX(0)} 20%{transform:translateX(-4px)}
  40%{transform:translateX(4px)}  60%{transform:translateX(-3px)}
  80%{transform:translateX(3px)}
}

/* Thick borders for 3x3 boxes */
.cell.bb-right  { border-right: 2.5px solid var(--violet2); }
.cell.bb-bottom { border-bottom: 2.5px solid var(--violet2); }

.cell-val {
  font-family: 'Playfair Display', serif;
  font-size: clamp(1rem, 3.5cqw, 1.6rem);
  font-weight: 600;
  color: var(--text2);
  line-height: 1;
}
.cell.locked .cell-val { color: var(--text); font-weight: 700; }

/* Notes */
.notes-grid {
  display: grid; grid-template-columns: repeat(3,1fr);
  width: 92%; height: 92%; gap: 0;
}
.note {
  display: flex; align-items: center; justify-content: center;
  font-size: clamp(0.28rem, 1.1cqw, 0.55rem);
  font-weight: 500;
  color: transparent;
}
.note.on { color: var(--violet); }

/* ── Win Overlay ── */
.win-overlay {
  position: absolute; inset: 0;
  background: rgba(8,8,18,0.88);
  backdrop-filter: blur(10px);
  display: flex; align-items: center; justify-content: center;
  z-index: 20; border-radius: calc(var(--r) - 2px);
  animation: fadeIn 0.3s ease;
}
@keyframes fadeIn { from{opacity:0;transform:scale(0.95)} to{opacity:1;transform:scale(1)} }
.win-card { text-align: center; padding: 48px 32px; }
.confetti-row { font-size: 2.2rem; margin-bottom: 16px; display:flex; gap:8px; justify-content:center; }
.confetti-row span { display:inline-block; animation: floatUp 0.6s ease both; }
@keyframes floatUp { from{transform:translateY(20px);opacity:0} to{transform:translateY(0);opacity:1} }
.win-title {
  font-family: 'Playfair Display', serif; font-size: 2.8rem;
  background: linear-gradient(135deg, var(--gold), var(--violet));
  -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
  margin-bottom: 10px;
}
.win-details { color: var(--text2); font-size: 1rem; margin-bottom: 8px; }
.win-details strong { color: var(--text); }
.win-rating { font-size: 1.3rem; margin-bottom: 24px; }

/* ── Side Panel ── */
.side {
  display: flex; flex-direction: column; gap: 18px;
  width: 230px; flex-shrink: 0;
}
.section-label {
  font-size: 0.75rem; font-weight: 600;
  color: var(--text3); letter-spacing: 0.12em;
  text-transform: uppercase; margin-bottom: 8px;
}

/* Number pad */
.numpad {
  display: grid; grid-template-columns: repeat(5,1fr); gap: 8px;
}
.nkey {
  aspect-ratio: 1;
  background: var(--card); border: 1.5px solid var(--border2);
  color: var(--text); border-radius: 10px;
  cursor: pointer; transition: all 0.14s;
  display: flex; flex-direction: column;
  align-items: center; justify-content: center; gap: 1px;
}
.nkey:hover:not(:disabled) {
  background: var(--violet2); border-color: var(--violet);
  transform: translateY(-2px);
  box-shadow: 0 4px 14px rgba(128,112,248,0.35);
}
.nkey.done { opacity: 0.28; cursor: default; }
.nkey-num { font-family: 'Playfair Display', serif; font-size: 1.25rem; font-weight: 600; line-height: 1; }
.nkey-count { font-size: 0.55rem; color: var(--text3); letter-spacing: 0.04em; }
.erase-key {
  background: rgba(255,90,90,0.08); border-color: rgba(255,90,90,0.25);
  color: var(--err); font-size: 1.1rem; font-family: 'DM Sans';
}
.erase-key:hover:not(:disabled) {
  background: rgba(255,90,90,0.18); border-color: var(--err);
  box-shadow: 0 4px 14px rgba(255,90,90,0.25); transform: translateY(-2px);
}

/* Action buttons */
.actions { display: flex; gap: 8px; }
.action-btn {
  flex: 1; padding: 9px 4px;
  background: var(--card); border: 1.5px solid var(--border2);
  color: var(--text2); border-radius: 10px;
  font-family: 'DM Sans'; font-size: 0.78rem;
  cursor: pointer; transition: all 0.14s;
  display: flex; flex-direction: column; align-items: center; gap: 4px;
}
.action-btn:hover:not(:disabled) { border-color: var(--teal); color: var(--teal); }
.action-btn:disabled { opacity: 0.3; cursor: default; }
.action-btn.active-note { background: rgba(62,207,202,0.12); border-color: var(--teal); color: var(--teal); }
.hint-action:hover:not(:disabled) { border-color: var(--gold); color: var(--gold); }

/* Progress */
.progress-card {
  background: var(--card); border: 1px solid var(--border2);
  border-radius: var(--r); padding: 16px;
}
.progress-header {
  display: flex; justify-content: space-between;
  font-size: 0.8rem; font-weight: 600;
  color: var(--text3); text-transform: uppercase; letter-spacing: 0.08em;
  margin-bottom: 10px;
}
.progress-pct { color: var(--teal); }
.progress-track {
  height: 8px; background: var(--border2);
  border-radius: 8px; overflow: hidden; margin-bottom: 8px;
}
.progress-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--violet), var(--teal));
  border-radius: 8px; transition: width 0.4s ease;
}
.progress-counts {
  display: flex; justify-content: space-between;
  font-size: 0.78rem; color: var(--text3);
}

/* Tip card */
.tip-card {
  background: var(--card); border: 1px solid var(--border2);
  border-radius: var(--r); padding: 16px;
}
.tip-badge {
  display: inline-block;
  font-size: 0.72rem; font-weight: 600;
  color: var(--gold); letter-spacing: 0.1em;
  text-transform: uppercase; margin-bottom: 8px;
}
.tip-title {
  font-family: 'Playfair Display', serif;
  font-size: 1rem; font-weight: 600;
  color: var(--text); margin-bottom: 6px;
}
.tip-body {
  font-size: 0.85rem; color: var(--text2);
  line-height: 1.65; min-height: 56px;
}
.tip-next {
  margin-top: 12px; background: none; border: none;
  color: var(--violet); font-family: 'DM Sans'; font-size: 0.82rem;
  cursor: pointer; padding: 0; transition: color 0.15s;
}
.tip-next:hover { color: var(--gold); }

/* ── Responsive ── */
@media (max-width: 640px) {
  .side { width: 100%; max-width: 504px; }
  .numpad { grid-template-columns: repeat(5,1fr); }
  .game-layout { gap: 20px; }
  .logo-text { font-size: 1.6rem; }
}
